  dictionary = {"A": "|_| ", "a": "|_| ", "B": "|-| ", "b": "|-| ", "C": "* ", "c": "* ", "D": "/| ", "d": "/| ", "E": "-+- ", "e": "-+- ", "F": "||| ", "f": "||| ", "G": '"" ', "g": '"" ', "H": '" ', "h": '" ', "I": "# ", "i": "# ", "J": "/–- ", "j": "/–- ", "K": "]_[ ", "k": "]_[ ", "L": "• ", "l": "• ", "M": "~ ", "m": "~ ", "N": "()+() ", "n": "()+() ", "O": "00 ", "o": "00 ", "P": "!;! ", "p": "!;! ", "Q": "@, ", "q": "@, ", "R": "+-+ ", "r": "+-+ ", "S": "?,? ", "s": "?,? ", "T": "!!!-!!! ", "t": "!!!-!!! ", "U": "() ", "u": "() ", "V": "€£ ", "v": "€£ ", "W": "Vn ", "w": "Vn ", "X": "'› ", "x": "'› ", "Y": "‹› ", "y": "‹› ", "Z": "0 ", "z": "0 "}
  table = str.maketrans(dictionary)
